<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">OPT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PSEUDOSECTION:</span></span>
